import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { useAuth } from "../contexts/AuthContext";

export default function Login() {
  const navigate = useNavigate();
  const { login: loginUser } = useAuth();

  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1); // 1 = enter mobile, 2 = enter OTP
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  // Validate mobile number with optional +91
  const isValidMobile = (num) => {
    const cleaned = num.replace(/\s+/g, ""); // remove spaces
    const pattern = /^(\+91)?[6-9]\d{9}$/; // allow +91 prefix
    return pattern.test(cleaned);
  };

  const handleSendOtp = async () => {
    if (!isValidMobile(mobile)) {
      setError("Enter a valid 10-digit mobile number (with optional +91)");
      return;
    }
    setLoading(true);
    setError("");
    try {
      // Remove +91 before sending to backend
      const sendMobile = mobile.startsWith("+91") ? mobile.slice(3) : mobile;
      await axios.post("http://localhost:5000/api/otp/send-otp", { mobile: sendMobile });
      setStep(2);
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to send OTP");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setLoading(true);
    setError("");
    try {
      const verifyMobile = mobile.startsWith("+91") ? mobile.slice(3) : mobile;
      const res = await axios.post("http://localhost:5000/api/otp/verify-otp", { mobile: verifyMobile, otp });
      if (res.data?.success) {
        loginUser(res.data.data.user); // update context
        localStorage.setItem("token", res.data.data.token);
        navigate("/booking");
      } else {
        setError(res.data?.message || "OTP verification failed");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered", fontWeight: "bold" }}>
          Rider App
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        {step === 1 && (
          <>
            <TextField
              fullWidth
              type="tel"
              label="Mobile Number (+91 optional)"
              value={mobile}
              onChange={(e) => {
                let value = e.target.value.replace(/\D/g, ""); // keep digits only
                if (mobile.startsWith("+91")) value = "+91" + value; // retain +91 if typed
                setMobile(value.slice(0, mobile.startsWith("+91") ? 13 : 10));
              }}
              margin="normal"
              placeholder="e.g. +917799231212 or 7799231212"
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={handleSendOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Send OTP"}
            </Button>
          </>
        )}

        {step === 2 && (
          <>
            <TextField
              fullWidth
              type="tel"
              label="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value.replace(/\D/g, "").slice(0, 6))}
              margin="normal"
              inputProps={{ maxLength: 6 }}
            />
            <Button
              fullWidth
              variant="contained"
              sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
              onClick={handleVerifyOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Verify OTP"}
            </Button>
          </>
        )}

        {/* Signup button */}
        <Typography align="center" sx={{ mt: 3 }}>
          Don't have an account?{" "}
          <Button variant="text" sx={{ color: "orangered" }} onClick={() => navigate("/register")}>
            Signup
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
